compliant:
#include <stdexcept>

// Custom specific exception
class InvalidFilenameException : public std::invalid_argument {
public:
    InvalidFilenameException(const std::string& msg) : std::invalid_argument(msg) {}
};

// Compliant: Throwing specific exception
void processFile(const std::string& filename) {
    if (filename.empty()) {
        throw InvalidFilenameException("Filename cannot be empty");
    }
    // Process file
}

// Another compliant example using standard specific exception
void validateInput(int value) {
    if (value < 0) {
        throw std::invalid_argument("Value must be non-negative");
    }
}

// Compliant: Using specific domain_error for mathematical operations
void divide(int a, int b) {
    if (b == 0) {
        throw std::domain_error("Division by zero is undefined");
    }
}

// Custom exception hierarchy
class FileOperationException : public std::runtime_error {
public:
    FileOperationException(const std::string& msg) : std::runtime_error(msg) {}
};

class FileNotFoundException : public FileOperationException {
public:
    FileNotFoundException(const std::string& filename) 
        : FileOperationException("File not found: " + filename) {}
};
